[JSON Schema]
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "PsyClaw Flowchart Project",
  "description": "JSON schema for PsyClaw flowchart projects that convert to PsychoPy .psyexp format",
  "type": "object",
  "required": [
    "version",
    "timestamp",
    "routineRects",
    "connections"
  ],
  "additionalProperties": false,
  "properties": {
    "version": {
      "type": "string",
      "description": "Schema version identifier",
      "examples": [
        "1.0.0"
      ]
    },
    "timestamp": {
      "type": "string",
      "format": "date-time",
      "description": "ISO 8601 datetime string when the project was created/updated"
    },
    "routineRects": {
      "type": "array",
      "description": "Array of routine objects representing experiment trials",
      "minItems": 1,
      "items": {
        "$ref": "#/definitions/Routine"
      }
    },
    "connections": {
      "type": "array",
      "description": "Array of connection objects defining the experiment flow",
      "items": {
        "$ref": "#/definitions/Connection"
      }
    },
    "currentRoutineCount": {
      "type": "integer",
      "description": "Current number of routines in the project",
      "minimum": 0,
      "default": 0
    },
    "routineIdCounter": {
      "type": "integer",
      "description": "Counter for generating unique routine IDs",
      "minimum": 0,
      "default": 0
    },
    "loopIdCounter": {
      "type": "integer",
      "description": "Counter for generating unique loop IDs",
      "minimum": 0,
      "default": 0
    }
  },
  "definitions": {
    "Routine": {
      "type": "object",
      "description": "A routine representing a single trial/stimulus presentation in PsychoPy",
      "required": [
        "id",
        "name",
        "x",
        "y",
        "width",
        "height"
      ],
      "additionalProperties": false,
      "properties": {
        "id": {
          "type": "integer",
          "description": "Unique identifier for the routine",
          "minimum": 0
        },
        "name": {
          "type": "string",
          "description": "Display name of the routine",
          "pattern": "^[a-zA-Z_][a-zA-Z0-9_]*$"
        },
        "x": {
          "type": "number",
          "description": "X coordinate position on the canvas"
        },
        "y": {
          "type": "number",
          "description": "Y coordinate position on the canvas"
        },
        "width": {
          "type": "number",
          "description": "Width of the routine rectangle",
          "minimum": 50
        },
        "height": {
          "type": "number",
          "description": "Height of the routine rectangle",
          "minimum": 50
        },
        "borderRadius": {
          "type": "number",
          "description": "Border radius for rounded corners",
          "minimum": 0,
          "default": 8
        },
        "isDragging": {
          "type": "boolean",
          "description": "Whether the routine is currently being dragged",
          "default": false
        },
        "offsetX": {
          "type": "number",
          "description": "X offset for drag operation"
        },
        "offsetY": {
          "type": "number",
          "description": "Y offset for drag operation"
        },
        "keys": {
          "type": "string",
          "description": "Comma-separated key names for keyboard responses",
          "examples": [
            "f",
            "j",
            "space"
          ]
        },
        "duration": {
          "type": "integer",
          "description": "Default duration in milliseconds (-1 for indefinite)",
          "minimum": -1,
          "default": -1
        },
        "avtp": {
          "$ref": "#/definitions/AVTPFlags"
        },
        "avtpData": {
          "$ref": "#/definitions/AVTPData"
        },
        "avtpComponents": {
          "type": "array",
          "description": "Alternative array-based component configuration",
          "items": {
            "$ref": "#/definitions/AvtpComponent"
          }
        },
        "type": {
          "type": "string",
          "description": "Legacy type designation (Audio, Text, Image, Keyboard, Code)",
          "enum": [
            "Audio",
            "Text",
            "Image",
            "Keyboard",
            "Code"
          ]
        }
      }
    },
    "AvtpComponent": {
      "type": "object",
      "description": "A component within a routine using array-based configuration",
      "required": [
        "enabled",
        "type"
      ],
      "additionalProperties": false,
      "properties": {
        "enabled": {
          "type": "boolean",
          "description": "Whether this component is enabled"
        },
        "type": {
          "type": "string",
          "description": "Component type",
          "enum": [
            "audio",
            "video",
            "text",
            "image",
            "keyboard"
          ]
        },
        "name": {
          "type": "string",
          "description": "Component name/label"
        },
        "path": {
          "type": "string",
          "description": "File path for media components"
        },
        "text": {
          "type": "string",
          "description": "Text content for text components"
        },
        "color": {
          "type": "string",
          "description": "Color value (e.g., 'white', 'red', '#ffffff')"
        },
        "font": {
          "type": "string",
          "description": "Font family name"
        },
        "letterHeight": {
          "type": "number",
          "description": "Font size in height units",
          "default": 0.05
        },
        "pos": {
          "type": "array",
          "description": "Position [x, y]",
          "items": {
            "type": "number"
          },
          "minItems": 2,
          "maxItems": 2,
          "default": [
            0,
            0
          ]
        },
        "size": {
          "type": "array",
          "description": "Size [width, height] (null values auto-calculate)",
          "items": {
            "type": [
              "number",
              "null"
            ]
          },
          "minItems": 2,
          "maxItems": 2
        },
        "ori": {
          "type": "number",
          "description": "Orientation in degrees",
          "default": 0
        },
        "opacity": {
          "type": "number",
          "description": "Opacity value",
          "minimum": 0,
          "maximum": 1,
          "default": 1
        },
        "volume": {
          "type": "number",
          "description": "Volume for audio/video",
          "minimum": 0,
          "maximum": 1,
          "default": 1
        },
        "startTime": {
          "type": "number",
          "description": "Start time in milliseconds",
          "minimum": 0,
          "default": 0
        },
        "duration": {
          "type": "number",
          "description": "Duration in milliseconds (-1 for indefinite)",
          "minimum": -1,
          "default": -1
        },
        "stopWithRoutine": {
          "type": "boolean",
          "description": "Whether to stop when routine ends",
          "default": true
        },
        "forceEndRoutine": {
          "type": "boolean",
          "description": "Whether to force end routine on response",
          "default": false
        },
        "keys": {
          "type": "string",
          "description": "Comma-separated keyboard keys"
        },
        "loop": {
          "type": "boolean",
          "description": "Whether to loop video/audio",
          "default": false
        },
        "contrast": {
          "type": "number",
          "description": "Contrast value",
          "minimum": 0,
          "maximum": 1,
          "default": 1
        },
        "flip": {
          "type": "string",
          "description": "Flip mode",
          "enum": [
            "None",
            "Horizontal",
            "Vertical",
            "Both"
          ],
          "default": "None"
        },
        "units": {
          "type": "string",
          "description": "Units for positioning",
          "enum": [
            "from exp settings",
            "height",
            "norm",
            "pix",
            "cm",
            "deg"
          ],
          "default": "from exp settings"
        },
        "languageStyle": {
          "type": "string",
          "description": "Language direction",
          "enum": [
            "LTR",
            "RTL"
          ],
          "default": "LTR"
        },
        "wrapWidth": {
          "type": "number",
          "description": "Text wrap width"
        },
        "anchor": {
          "type": "string",
          "description": "Anchor point for positioning",
          "enum": [
            "center",
            "top-center",
            "bottom-center",
            "left-center",
            "right-center",
            "top-left",
            "top-right",
            "bottom-left",
            "bottom-right"
          ],
          "default": "center"
        },
        "interpolate": {
          "type": "string",
          "description": "Image interpolation method",
          "enum": [
            "linear",
            "nearest"
          ],
          "default": "linear"
        },
        "textureRes": {
          "type": "integer",
          "description": "Texture resolution for images",
          "enum": [
            32,
            64,
            128,
            256,
            512
          ],
          "default": 128
        },
        "colorSpace": {
          "type": "string",
          "description": "Color space",
          "enum": [
            "rgb",
            "dkl",
            "hsv",
            "hex"
          ],
          "default": "rgb"
        },
        "draggable": {
          "type": "boolean",
          "description": "Whether the stimulus is draggable",
          "default": false
        },
        "hamming": {
          "type": "boolean",
          "description": "Apply Hamming window to audio",
          "default": true
        },
        "discardPrevious": {
          "type": "boolean",
          "description": "Discard previous key presses",
          "default": true
        },
        "registerOn": {
          "type": "string",
          "description": "When to register key press",
          "enum": [
            "press",
            "release"
          ],
          "default": "press"
        },
        "store": {
          "type": "string",
          "description": "What to store",
          "enum": [
            "last key",
            "all keys",
            "nothing"
          ],
          "default": "last key"
        },
        "storeCorrect": {
          "type": "boolean",
          "description": "Store whether response was correct",
          "default": false
        },
        "deviceLabel": {
          "type": "string",
          "description": "Audio device label"
        }
      }
    },
    "AVTPFlags": {
      "type": "object",
      "description": "Flags indicating which AVTP components are enabled",
      "required": [
        "a",
        "v",
        "t",
        "p",
        "k"
      ],
      "additionalProperties": false,
      "properties": {
        "a": {
          "type": "boolean",
          "description": "Audio component enabled"
        },
        "v": {
          "type": "boolean",
          "description": "Video component enabled"
        },
        "t": {
          "type": "boolean",
          "description": "Text component enabled"
        },
        "p": {
          "type": "boolean",
          "description": "Picture/Image component enabled"
        },
        "k": {
          "type": "boolean",
          "description": "Keyboard component enabled"
        }
      }
    },
    "AVTPData": {
      "type": "object",
      "description": "Configuration data for AVTP components",
      "additionalProperties": false,
      "properties": {
        "a": {
          "$ref": "#/definitions/AudioConfig"
        },
        "v": {
          "$ref": "#/definitions/VideoConfig"
        },
        "t": {
          "$ref": "#/definitions/TextConfig"
        },
        "p": {
          "$ref": "#/definitions/PictureConfig"
        },
        "k": {
          "$ref": "#/definitions/KeyboardConfig"
        }
      }
    },
    "TextConfig": {
      "type": "object",
      "description": "Configuration for text stimulus",
      "additionalProperties": false,
      "properties": {
        "enabled": {
          "type": "boolean",
          "description": "Whether this component is active"
        },
        "label": {
          "type": "string",
          "description": "Component label"
        },
        "type": {
          "type": "string",
          "const": "text",
          "description": "Component type discriminator"
        },
        "text": {
          "type": "string",
          "description": "Text content to display"
        },
        "font": {
          "type": "string",
          "description": "Font family",
          "default": "Arial"
        },
        "letterHeight": {
          "type": "number",
