            "pix",
            "cm",
            "deg"
          ],
          "default": "from exp settings"
        },
        "startTime": {
          "type": "number",
          "minimum": 0,
          "default": 0
        },
        "duration": {
          "type": "number",
          "minimum": -1,
          "default": -1
        },
        "contrast": {
          "type": "number",
          "minimum": 0,
          "maximum": 1,
          "default": 1
        },
        "wrapWidth": {
          "type": "number",
          "description": "Width for text wrapping"
        },
        "flip": {
          "type": "string",
          "enum": [
            "None",
            "Horizontal",
            "Vertical",
            "Both"
          ],
          "default": "None"
        },
        "languageStyle": {
          "type": "string",
          "enum": [
            "LTR",
            "RTL"
          ],
          "default": "LTR"
        },
        "draggable": {
          "type": "boolean",
          "default": false
        }
      }
    },
    "PictureConfig": {
      "type": "object",
      "description": "Configuration for image/picture stimulus",
      "additionalProperties": false,
      "properties": {
        "enabled": {
          "type": "boolean"
        },
        "label": {
          "type": "string"
        },
        "type": {
          "type": "string",
          "const": "image"
        },
        "path": {
          "type": "string",
          "description": "Image file path"
        },
        "size": {
          "type": "array",
          "items": {
            "type": [
              "number",
              "null"
            ]
          },
          "minItems": 2,
          "maxItems": 2
        },
        "pos": {
          "type": "array",
          "items": {
            "type": "number"
          },
          "minItems": 2,
          "maxItems": 2,
          "default": [
            0,
