            "hex"
          ],
          "default": "rgb"
        },
        "contrast": {
          "type": "number",
          "minimum": 0,
          "maximum": 1,
          "default": 1
        },
        "interpolate": {
          "type": "string",
          "enum": [
            "linear",
            "nearest"
          ],
          "default": "linear"
        },
        "textureRes": {
          "type": "integer",
          "enum": [
