          "type": "boolean"
        },
        "label": {
          "type": "string"
        },
        "type": {
          "type": "string",
          "const": "audio"
        },
        "path": {
          "type": "string",
          "description": "Audio file path"
        },
        "volume": {
          "type": "number",
          "minimum": 0,
          "maximum": 1,
          "default": 1
        },
        "startTime": {
          "type": "number",
          "minimum": 0,
