        },
        "opacity": {
          "type": "number",
          "minimum": 0,
          "maximum": 1,
          "default": 1
        },
        "stopWithRoutine": {
          "type": "boolean",
          "default": true
        },
        "forceEndRoutine": {
          "type": "boolean",
          "default": false
        }
      }
    },
    "KeyboardConfig": {
      "type": "object",
      "description": "Configuration for keyboard response component",
      "additionalProperties": false,
      "properties": {
        "enabled": {
          "type": "boolean"
        },
        "label": {
          "type": "string"
        },
        "type": {
          "type": "string",
          "const": "keyboard"
        },
        "keys": {
          "type": "string",
          "description": "Comma-separated keyboard keys",
          "examples": [
            "f,j",
            "space,enter",
            "'f','j'"
          ]
        },
        "startTime": {
          "type": "number",
          "minimum": 0,
          "default": 0
        },
        "duration": {
          "type": "number",
          "minimum": -1,
          "default": -1
        },
        "forceEndRoutine": {
          "type": "boolean",
          "default": false
        },
        "discardPrevious": {
          "type": "boolean",
