          "type": "string",
          "const": "code"
        },
        "code": {
          "type": "string",
          "description": "Python code to execute"
        },
        "codeType": {
          "type": "string",
          "enum": [
            "Py",
            "JS",
            "Both"
          ],
          "default": "Py"
        }
      }
    },
    "Connection": {
      "type": "object",
      "description": "A connection object defining flow between routines. For simple sequential flow, only start and end are required.",
      "required": [
        "start",
        "end"
      ],
      "additionalProperties": false,
      "properties": {
        "start": {
          "$ref": "#/definitions/ConnectionEndpoint"
        },
        "end": {
          "$ref": "#/definitions/ConnectionEndpoint"
        },
        "depth": {
          "type": "integer",
          "minimum": 0,
          "description": "Nesting depth for loops (0 for normal flow, 1+ for loops)",
          "default": 0
        },
        "loopName": {
          "type": "string",
          "description": "Name of the loop (only needed if this connection creates a trial loop)"
        },
        "loopReps": {
          "type": "integer",
          "minimum": 1,
          "description": "Number of loop repetitions (only for trial loops)",
          "default": 1
        },
        "loopType": {
          "type": "string",
          "enum": [
            "sequential",
            "random"
          ],
          "description": "Loop type for trial loops",
          "default": "sequential"
        },
        "loopConditions": {
          "type": "string",
          "description": "Conditions file path or JSON array string for loop"
        },
        "loopIsTrials": {
          "type": "boolean",
          "description": "Whether this loop is a trial handler",
          "default": false
        }
      }
    },
    "ConnectionEndpoint": {
      "type": "object",
      "description": "An endpoint of a connection representing a connection point on a routine",
      "required": [
        "routineId",
        "position"
      ],
      "additionalProperties": false,
      "properties": {
        "routineId": {
          "type": "integer",
          "description": "ID of the routine this endpoint connects to"
        },
        "position": {
          "type": "string",
          "enum": [
            "left",
            "right"
          ],
          "description": "Position of the connection point on the routine (left=exit, right=entry)"
        },
        "label": {
          "type": "string",
          "description": "Optional connection point label for visual identification"
        }
